// ── Splash Screen ─────────────────────────────────────────────────────────────
interface Props {
  onFinish?: () => void;
}

const SplashScreen: React.FC<Props> = ({ onFinish }) => {
  const fadeAnim  = useRef(new Animated.Value(0)).current;
  const scaleAnim = useRef(new Animated.Value(0.9)).current;
  const exitAnim  = useRef(new Animated.Value(1)).current;

  // Logo is 1015x424 — scale to 90% screen width, preserve aspect ratio
  const logoWidth  = Math.min(SW * 0.90, 420);
  const logoHeight = logoWidth * (424 / 1015);

  useEffect(() => {
    Animated.sequence([
      // Pop in
      Animated.parallel([
        Animated.timing(fadeAnim, {
          toValue: 1,
          duration: 600,
          easing: Easing.out(Easing.cubic),
          useNativeDriver: true,
        }),
        Animated.spring(scaleAnim, {
          toValue: 1,
          friction: 7,
          tension: 50,
          useNativeDriver: true,
        }),
      ]),
      // Hold
      Animated.delay(1500),
      // Fade out
      Animated.timing(exitAnim, {
        toValue: 0,
        duration: 500,
        easing: Easing.in(Easing.ease),
        useNativeDriver: true,
      }),
    ]).start(() => {
      onFinish?.();
      // navigation.replace('Landing');
    });
  }, []);

  return (
    <Animated.View style={[styles.container, { opacity: exitAnim }]}>
      <StatusBar barStyle="dark-content" backgroundColor="#FFFFFF" />
      <Animated.View
        style={{
          opacity: fadeAnim,
          transform: [{ scale: scaleAnim }],
        }}
      >
        <SvgXml
          xml={LOGO_SVG}
          width={logoWidth}
          height={logoHeight}
        />
      </Animated.View>
    </Animated.View>
  );
};

export default SplashScreen;

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#FFFFFF',
    justifyContent: 'center',
    alignItems: 'center',
  },
});

/*
 * ── Setup ────────────────────────────────────────────────────
 *  npm install react-native-svg
 *  cd ios && pod install
 *
 *  Wire into AppNavigator as the first screen:
 *    <RootStack.Screen
 *      name="Splash"
 *      component={SplashScreen}
 *      options={{ headerShown: false, gestureEnabled: false }}
 *    />
 *    initialRouteName="Splash"
 *
 *  Then uncomment: navigation.replace('Landing');
 *
 *  Note: SvgXml renders the full SVG including the embedded
 *  base64 PNG logo image and black text paths.
 *  Background is white (#FFFFFF) to suit the black text.
 * ────────────────────────────────────────────────────────────
 */
